'use client'

import { useState } from 'react'
import { Flame, Star, Heart, ChevronRight, Lock, CheckCircle2, Circle, TrendingUp } from 'lucide-react'

interface UserProfile {
  userType: 'child' | 'parent'
  age?: number
  disorders: string[]
  completedAssessment: boolean
}

interface MainDashboardProps {
  userProfile: UserProfile
  onNavigate: (screen: string) => void
}

interface LessonNode {
  id: string
  title: string
  type: 'warm-up' | 'practice' | 'challenge'
  game: string
  completed: boolean
  locked: boolean
  level: number
}

export default function MainDashboard({ userProfile, onNavigate }: MainDashboardProps) {
  const [streak, setStreak] = useState(5)
  const [stars, setStars] = useState(240)
  const [hearts, setHearts] = useState(5)

  // Path-based lessons (Duolingo style)
  const lessons: LessonNode[] = [
    {
      id: 'warm-up',
      title: 'Warm Up',
      type: 'warm-up',
      game: 'warm-up',
      completed: false,
      locked: false,
      level: 1,
    },
    {
      id: 'bubble-pop-1',
      title: 'Bubble Pop',
      type: 'practice',
      game: 'bubble-pop',
      completed: false,
      locked: false,
      level: 2,
    },
    {
      id: 'bubble-pop-2',
      title: 'Advanced Sounds',
      type: 'practice',
      game: 'bubble-pop',
      completed: false,
      locked: true,
      level: 3,
    },
    {
      id: 'challenge-1',
      title: 'Speed Challenge',
      type: 'challenge',
      game: 'bubble-pop',
      completed: false,
      locked: true,
      level: 4,
    },
  ]

  const getNodeColor = (lesson: LessonNode) => {
    if (lesson.locked) return '#E5E7EB'
    if (lesson.completed) return '#2A9896'
    if (lesson.type === 'warm-up') return '#4ADEC0'
    if (lesson.type === 'practice') return '#EE8B44'
    return '#152341'
  }

  const getNodeBgColor = (lesson: LessonNode) => {
    if (lesson.locked) return '#F5F7FA'
    if (lesson.completed) return '#E0F5F4'
    if (lesson.type === 'warm-up') return '#E6FBF8'
    if (lesson.type === 'practice') return '#FFF4ED'
    return '#F5F7FA'
  }

  const getGreeting = () => {
    const hour = new Date().getHours()
    if (hour < 12) return 'Good Morning'
    if (hour < 18) return 'Good Afternoon'
    return 'Good Evening'
  }

  return (
    <div className="min-h-screen bg-white">
      {/* Top Header Bar */}
      <div className="bg-white border-b border-[#E5E7EB] sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 py-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-[#EE8B44] to-[#FFA366] flex items-center justify-center">
                <span className="text-white font-bold text-sm">SF</span>
              </div>
              <div>
                <p className="text-xs text-[#6B7280] font-medium">{getGreeting()}</p>
                <p className="text-sm font-semibold text-[#152341]">Ready to practice?</p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              {/* Streak */}
              <div className="flex items-center gap-1.5 bg-[#FFF4ED] px-3 py-1.5 rounded-full border border-[#EE8B44]/20">
                <Flame className="w-4 h-4 text-[#EE8B44]" />
                <span className="text-sm font-bold text-[#152341]">{streak}</span>
            </div>

            {/* Stars */}
              <div className="flex items-center gap-1.5 bg-[#E0F5F4] px-3 py-1.5 rounded-full border border-[#2A9896]/20">
                <Star className="w-4 h-4 text-[#2A9896] fill-[#2A9896]" />
                <span className="text-sm font-bold text-[#152341]">{stars}</span>
            </div>

            {/* Hearts */}
              <div className="flex items-center gap-1.5 bg-[#E6FBF8] px-3 py-1.5 rounded-full border border-[#4ADEC0]/20">
                <Heart className="w-4 h-4 text-[#4ADEC0] fill-[#4ADEC0]" />
                <span className="text-sm font-bold text-[#152341]">{hearts}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content - Path View */}
      <div className="max-w-6xl mx-auto px-4 sm:px-6 py-8">
        {/* Progress Overview */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-2">
            <h1 className="text-2xl font-bold text-[#152341]">Your Learning Path</h1>
            <div className="flex items-center gap-2 text-sm text-[#6B7280]">
              <TrendingUp className="w-4 h-4" />
              <span>2 of 4 lessons completed</span>
            </div>
          </div>
          <div className="w-full bg-[#F5F7FA] rounded-full h-2 overflow-hidden">
            <div
              className="h-full bg-gradient-to-r from-[#EE8B44] to-[#2A9896] rounded-full transition-all duration-500"
              style={{ width: '50%' }}
            />
          </div>
        </div>

        {/* Learning Path */}
        <div className="relative">
          {/* Path Line */}
          <div className="absolute left-8 top-0 bottom-0 w-0.5 bg-[#E5E7EB] hidden sm:block" 
               style={{ marginTop: '40px', marginBottom: '40px' }} />

          {/* Lesson Nodes */}
          <div className="space-y-6">
            {lessons.map((lesson, index) => {
              const nodeColor = getNodeColor(lesson)
              const nodeBgColor = getNodeBgColor(lesson)
              const isLast = index === lessons.length - 1

              return (
                <div key={lesson.id} className="relative flex items-center gap-6">
                  {/* Node Circle */}
                  <div className="relative z-10 flex-shrink-0">
          <button
                      onClick={() => !lesson.locked && onNavigate(lesson.game)}
                      disabled={lesson.locked}
                      className={`
                        w-16 h-16 rounded-full flex items-center justify-center
                        transition-all duration-300
                        ${lesson.locked 
                          ? 'bg-[#F5F7FA] border-2 border-[#E5E7EB] cursor-not-allowed' 
                          : lesson.completed
                          ? 'bg-[#2A9896] border-2 border-[#2A9896] shadow-lg hover:scale-110'
                          : 'bg-white border-2 border-[#EE8B44] shadow-md hover:scale-110 hover:shadow-xl'
                        }
                      `}
            style={{
                        borderColor: lesson.locked ? '#E5E7EB' : nodeColor,
                      }}
                    >
                      {lesson.completed ? (
                        <CheckCircle2 className="w-8 h-8 text-white" />
                      ) : lesson.locked ? (
                        <Lock className="w-6 h-6 text-[#9CA3AF]" />
                      ) : (
                        <div 
                          className="w-8 h-8 rounded-full"
                          style={{ backgroundColor: nodeColor }}
                        />
                      )}
                    </button>
                    
                    {/* Level Badge */}
                    {!lesson.locked && (
                      <div 
                        className="absolute -top-1 -right-1 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold text-white"
                        style={{ backgroundColor: nodeColor }}
                      >
                        {lesson.level}
                      </div>
                    )}
                  </div>

                  {/* Lesson Card */}
                  <div className="flex-1">
                    <button
                      onClick={() => !lesson.locked && onNavigate(lesson.game)}
                      disabled={lesson.locked}
                      className={`
                        w-full text-left p-5 rounded-xl border-2 transition-all duration-300
                        ${lesson.locked
                          ? 'bg-[#F9FAFB] border-[#E5E7EB] cursor-not-allowed'
                          : lesson.completed
                          ? 'bg-[#E0F5F4] border-[#2A9896] hover:shadow-lg hover:scale-[1.02]'
                          : 'bg-white border-[#EE8B44] hover:shadow-xl hover:scale-[1.01]'
                        }
                      `}
                    >
                      <div className="flex items-start justify-between">
              <div className="flex-1">
                          <div className="flex items-center gap-2 mb-2">
                            <span 
                              className="text-xs font-bold uppercase tracking-wider px-2 py-1 rounded"
                              style={{
                                backgroundColor: lesson.locked ? '#F5F7FA' : nodeBgColor,
                                color: lesson.locked ? '#9CA3AF' : nodeColor,
                              }}
                            >
                              {lesson.type === 'warm-up' ? 'Warm Up' : 
                               lesson.type === 'practice' ? 'Practice' : 'Challenge'}
                            </span>
                            {lesson.completed && (
                              <span className="text-xs text-[#2A9896] font-semibold">Completed</span>
                            )}
                          </div>
                          <h3 className={`text-xl font-bold mb-1 ${
                            lesson.locked ? 'text-[#9CA3AF]' : 'text-[#152341]'
                          }`}>
                            {lesson.title}
                </h3>
                          <p className={`text-sm ${
                            lesson.locked ? 'text-[#9CA3AF]' : 'text-[#6B7280]'
                          }`}>
                            {lesson.type === 'warm-up' && 'Prepare your mouth for practice'}
                            {lesson.type === 'practice' && 'Practice pronunciation with real-time feedback'}
                            {lesson.type === 'challenge' && 'Test your skills with advanced challenges'}
                </p>
              </div>
                        {!lesson.locked && (
                          <ChevronRight className={`w-5 h-5 flex-shrink-0 ml-4 ${
                            lesson.completed ? 'text-[#2A9896]' : 'text-[#EE8B44]'
                          }`} />
                        )}
                      </div>
                    </button>
              </div>
            </div>
              )
            })}
          </div>
        </div>

        {/* Daily Goal Card */}
        <div className="mt-12 bg-gradient-to-br from-[#FFF4ED] to-[#E6FBF8] rounded-2xl p-6 border border-[#E5E7EB]">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-bold text-[#152341]">Today's Goal</h2>
            <span className="text-sm font-semibold text-[#6B7280]">2 / 5 lessons</span>
          </div>
          <div className="w-full bg-white/60 rounded-full h-3 overflow-hidden mb-4">
            <div
              className="h-full bg-gradient-to-r from-[#EE8B44] to-[#2A9896] rounded-full transition-all duration-500"
              style={{ width: '40%' }}
            />
          </div>
          <p className="text-sm text-[#6B7280]">
            Complete 3 more lessons to reach your daily goal and maintain your streak!
          </p>
        </div>
      </div>
    </div>
  )
}
